import React, { useState, useEffect } from 'react';
import axios from 'axios';

export default function Marketplace() {
  const [loads, setLoads] = useState([]);
  const [formData, setFormData] = useState({
    origin: '',
    destination: '',
    weight: '',
    pallets: '',
    price: ''
  });

  // 1. Fetching Loads from Database
  const fetchLoads = async () => {
    try {
      const response = await axios.get("http://localhost:5000/api/loads/all");
      setLoads(response.data);
    } catch (error) {
      console.error("Error fetching loads:", error);
    }
  };

  useEffect(() => {
    fetchLoads();
  }, []);

  // 2. Handling Form Submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/loads/add", formData);
      alert("🚛 Load Posted Successfully!");
      setFormData({ origin: '', destination: '', weight: '', pallets: '', price: '' });
      fetchLoads(); // Refresh list after posting
    } catch (error) {
      alert("Failed to post load. Check console for details.");
    }
  };

  return (
    <div className="min-h-screen bg-yellow-50 p-6 font-sans">
      {/* Navbar */}
      <header className="flex justify-between items-center mb-8 bg-white p-5 rounded-xl shadow-sm border-b-4 border-truckYellow">
        <div className="flex items-center gap-2">
          <span className="text-3xl">🚛</span>
          <h1 className="text-2xl font-black italic tracking-tighter text-black">TRUCK LOAD BOARD</h1>
        </div>
        <nav className="font-bold text-sm uppercase tracking-widest text-gray-700">LTL Marketplace</nav>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Side: Post Form (4 Columns) */}
        <div className="lg:col-span-4">
          <div className="bg-white p-8 rounded-2xl shadow-xl border-t-8 border-truckRed sticky top-6">
            <h2 className="text-2xl font-black mb-6 uppercase italic text-gray-800">Post LTL Freight</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input 
                type="text" placeholder="Origin (e.g. Chennai)" required
                className="w-full p-4 border-2 border-gray-100 rounded-lg font-bold focus:border-truckYellow outline-none"
                value={formData.origin} onChange={(e) => setFormData({...formData, origin: e.target.value})}
              />
              <input 
                type="text" placeholder="Destination (e.g. Bangalore)" required
                className="w-full p-4 border-2 border-gray-100 rounded-lg font-bold focus:border-truckYellow outline-none"
                value={formData.destination} onChange={(e) => setFormData({...formData, destination: e.target.value})}
              />
              <div className="flex gap-4">
                <input 
                  type="number" placeholder="Weight (kg)"
                  className="w-1/2 p-4 border-2 border-gray-100 rounded-lg font-bold"
                  value={formData.weight} onChange={(e) => setFormData({...formData, weight: e.target.value})}
                />
                <input 
                  type="number" placeholder="Pallets"
                  className="w-1/2 p-4 border-2 border-gray-100 rounded-lg font-bold"
                  value={formData.pallets} onChange={(e) => setFormData({...formData, pallets: e.target.value})}
                />
              </div>
              <input 
                type="number" placeholder="Price ($)"
                className="w-full p-4 border-2 border-gray-100 rounded-lg font-bold"
                value={formData.price} onChange={(e) => setFormData({...formData, price: e.target.value})}
              />
              <button className="w-full bg-black text-white py-4 rounded-xl font-black uppercase tracking-widest hover:bg-gray-800 transition-all active:scale-95">
                Post Load
              </button>
            </form>
          </div>
        </div>

        {/* Right Side: Live Loads (8 Columns) */}
        <div className="lg:col-span-8">
          <h2 className="text-4xl font-black mb-8 italic uppercase tracking-tight text-black">
            Live Loads <span className="text-truckRed ml-2">●</span>
          </h2>
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {loads.length > 0 ? (
              loads.map((load) => (
                <div key={load._id} className="bg-white p-6 rounded-2xl border-b-8 border-black shadow-lg hover:-translate-y-2 transition-transform duration-300">
                  <div className="flex justify-between items-start mb-4">
                    <div className="bg-yellow-400 text-black text-[10px] font-black px-2 py-1 rounded uppercase">LTL Available</div>
                    <div className="text-2xl font-black text-green-600">${load.price}</div>
                  </div>
                  
                  <div className="space-y-2 mb-6">
                    <div className="flex items-center gap-3">
                      <div className="w-3 h-3 rounded-full bg-green-500"></div>
                      <p className="font-bold text-gray-800 uppercase tracking-wide">{load.origin}</p>
                    </div>
                    <div className="ml-1.5 h-6 border-l-2 border-dashed border-gray-300"></div>
                    <div className="flex items-center gap-3">
                      <div className="w-3 h-3 rounded-full bg-red-500"></div>
                      <p className="font-bold text-gray-800 uppercase tracking-wide">{load.destination}</p>
                    </div>
                  </div>

                  <div className="flex justify-between p-3 bg-gray-50 rounded-lg border border-gray-100">
                    <div className="text-center">
                      <p className="text-[10px] uppercase font-bold text-gray-400 leading-none">Weight</p>
                      <p className="font-black text-gray-700">{load.weight} kg</p>
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] uppercase font-bold text-gray-400 leading-none">Pallets</p>
                      <p className="font-black text-gray-700">{load.pallets}</p>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="col-span-full py-20 text-center bg-white rounded-3xl border-4 border-dashed border-gray-200">
                <p className="text-xl font-bold text-gray-400 italic">No loads posted yet. Start the market!</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
